const app = express();

// --- Security Middleware ---

// Set security HTTP headers (CSP, HSTS, X-Content-Type-Options, etc.)
app.use(helmet());

// Remove X-Powered-By header (helmet does this, but being explicit)
app.disable('x-powered-by');

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Parse URL-encoded bodies with a size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting — 100 requests per 15-minute window per IP
const limiter = rateLimit({
